import React from 'react';

function TechGlobeSection() {
  return (
    <section className="relative py-24 px-4 sm:px-6 lg:px-8 overflow-hidden bg-transparent">
      <div className="relative max-w-4xl mx-auto">
        {/* Title */}
        <div className="text-center mb-14">
          <h2 className="text-4xl font-bold text-gray-900 mb-4">Sản Phẩm Của Chúng Tôi</h2>
          <p className="text-gray-500 text-lg">Xem demo trực tiếp sản phẩm đã triển khai</p>
        </div>

        {/* Sphere + Video container */}
        <div className="relative flex items-center justify-center" style={{ minHeight: '550px' }}>

          {/* Sphere background - giống Agora */}
          <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
            <div className="relative" style={{ width: '700px', height: '700px' }}>
              {/* Outer sphere */}
              <div className="absolute inset-0 rounded-full" style={{
                background: 'radial-gradient(circle at 40% 40%, rgba(20, 25, 60, 0.95) 0%, rgba(10, 12, 30, 0.98) 50%, rgba(5, 5, 15, 0.95) 100%)',
                boxShadow: '0 0 80px rgba(56, 97, 251, 0.08), 0 0 160px rgba(139, 92, 246, 0.04)',
              }} />
              {/* Inner glow ring */}
              <div className="absolute inset-4 rounded-full" style={{
                background: 'radial-gradient(circle at 35% 35%, rgba(56, 97, 251, 0.06) 0%, transparent 60%)',
                border: '1px solid rgba(255,255,255,0.03)',
              }} />
              {/* Dot grid overlay */}
              <div className="absolute inset-0 rounded-full opacity-20" style={{
                backgroundImage: 'radial-gradient(rgba(255,255,255,0.15) 1px, transparent 1px)',
                backgroundSize: '12px 12px',
                mask: 'radial-gradient(circle, black 30%, transparent 70%)',
                WebkitMask: 'radial-gradient(circle, black 30%, transparent 70%)',
              }} />
              {/* Subtle purple arc */}
              <div className="absolute inset-8 rounded-full" style={{
                background: 'conic-gradient(from 200deg, transparent 0%, rgba(139, 92, 246, 0.05) 10%, transparent 20%)',
              }} />
            </div>
          </div>

          {/* Floating code snippets - left side */}
          <div className="absolute left-0 top-1/4 hidden lg:block z-10 pointer-events-none">
            <div className="bg-black/60 backdrop-blur-sm rounded-lg px-3 py-2 border border-white/5">
              <code className="text-xs text-cyan-300/70 font-mono">GnodSDK.init(appId);</code>
            </div>
            <div className="bg-black/60 backdrop-blur-sm rounded-lg px-3 py-2 border border-white/5 mt-2 ml-4">
              <code className="text-xs text-purple-300/70 font-mono">GnodSDK.enableVideo();</code>
            </div>
            <div className="bg-black/60 backdrop-blur-sm rounded-lg px-3 py-2 border border-white/5 mt-2">
              <code className="text-xs text-blue-300/70 font-mono">GnodSDK.joinChannel();</code>
            </div>
          </div>

          {/* Floating code snippets - right side */}
          <div className="absolute right-0 bottom-1/4 hidden lg:block z-10 pointer-events-none">
            <div className="bg-black/60 backdrop-blur-sm rounded-lg px-3 py-2 border border-white/5">
              <code className="text-xs text-cyan-300/70 font-mono">GnodContext.appId = &lt;Your AppId&gt;</code>
            </div>
            <div className="bg-black/60 backdrop-blur-sm rounded-lg px-3 py-2 border border-white/5 mt-2 mr-4">
              <code className="text-xs text-green-300/70 font-mono">GnodSDK.sendMessage(data);</code>
            </div>
          </div>

          {/* Video monitor - floating on sphere */}
          <div className="relative z-20" style={{ maxWidth: '680px', width: '100%' }}>
            <div className="rounded-xl overflow-hidden" style={{
              border: '1px solid rgba(255, 255, 255, 0.1)',
              boxShadow: '0 20px 60px rgba(0,0,0,0.5), 0 0 40px rgba(56, 97, 251, 0.08)',
            }}>
              {/* Browser bar */}
              <div className="flex items-center gap-2 px-4 py-2.5" style={{
                background: 'rgba(20, 20, 35, 0.95)',
                borderBottom: '1px solid rgba(255, 255, 255, 0.06)'
              }}>
                <div className="flex gap-1.5">
                  <div className="w-2.5 h-2.5 rounded-full bg-red-500/80" />
                  <div className="w-2.5 h-2.5 rounded-full bg-yellow-500/80" />
                  <div className="w-2.5 h-2.5 rounded-full bg-green-500/80" />
                </div>
                <div className="flex-1 flex justify-center">
                  <div className="px-3 py-0.5 rounded text-xs text-gray-500 flex items-center gap-1.5" style={{ background: 'rgba(255,255,255,0.04)', border: '1px solid rgba(255,255,255,0.05)' }}>
                    <svg className="w-2.5 h-2.5 text-green-400" fill="none" viewBox="0 0 24 24" stroke="currentColor" strokeWidth={2}><path strokeLinecap="round" strokeLinejoin="round" d="M12 15v2m-6 4h12a2 2 0 002-2v-6a2 2 0 00-2-2H6a2 2 0 00-2 2v6a2 2 0 002 2zm10-10V7a4 4 0 00-8 0v4h8z" /></svg>
                    gnodai.com
                  </div>
                </div>
              </div>
              {/* Video */}
              <div className="relative" style={{ aspectRatio: '16/9', background: '#000' }}>
                <video className="absolute inset-0 w-full h-full object-cover" autoPlay muted loop playsInline src="/videos/video%20laptop.mp4" />
              </div>
            </div>
          </div>
        </div>

        {/* Trusted by */}
        <div className="mt-8 text-center">
          <p className="text-gray-400 text-xs tracking-widest uppercase mb-4">Được tin dùng bởi nhiều doanh nghiệp</p>
          <div className="flex items-center justify-center gap-8 flex-wrap opacity-30">
            {['Client A', 'Client B', 'Client C', 'Client D'].map((name, i) => (
              <span key={i} className="text-gray-500 text-sm font-semibold tracking-wider">{name}</span>
            ))}
          </div>
        </div>
      </div>
    </section>
  );
}

export default TechGlobeSection;
